/**
 * File Name: i18n-adapter.ts — v1.0.0
 * Description: Adaptador de i18n do BTS Utilities.
 *              Instancia o core com os dicionários do plugin e exporta
 *              as funções de uso público: createI18n, getStrings, normalizeLocale.
 * Author: Jeferson Padilha (https://jepasa.com)
 */
import { createManager } from './i18n-core.min.js';
import { DEFAULT_LOCALE, GLOBAL_KEY, SHORT_TO_CANONICAL, ROOT_REF, getAdapterDictionaries, } from './i18n-conf.js';
// ─── Manager singleton do plugin ──────────────────────────────────────────────
const manager = createManager({
    /** Locale de fallback final — definido em i18n-conf.js */
    defaultLocale: DEFAULT_LOCALE,
    /** Chave global para dicionários externos — definida em i18n-conf.js */
    globalKey: GLOBAL_KEY,
    /** Atalhos de locale curto → canônico — definidos em i18n-conf.js */
    shortToCanonical: SHORT_TO_CANONICAL,
    /** Dicionários iniciais resolvidos no i18n-conf.js (ordem de OPTIONAL_LOCALES). */
    dictionaries: getAdapterDictionaries(),
    /** Referência ao objeto global do browser — definida em i18n-conf.js */
    rootRef: ROOT_REF,
});
// ─── API pública ──────────────────────────────────────────────────────────────
/**
 * Cria uma instância de i18n resolvendo o locale automaticamente ou via opções.
 *
 * @example
 * const i18n = createI18n({ language: 'pt-BR', autoLanguage: false });
 * i18n.t('menu.mainLabel', null, 'Menu');
 */
export const createI18n = (options) => manager.createI18n(options);
/**
 * Retorna o dicionário de strings para o locale informado.
 * Realiza fallback automático para `en-US` se o locale não for encontrado.
 */
export const getStrings = (locale) => manager.getStrings(locale);
/** Normaliza um locale para um dos formatos suportados pelo plugin. */
export const normalizeLocale = (locale, fallback) => manager.normalizeLocale(locale, fallback);
/** Registra um dicionário de locale em runtime (permite extensão por terceiros). */
export const registerLocale = (locale, strings) => manager.registerLocale(locale, strings);
/** Verifica se um locale (incluindo variações equivalentes) já está registrado. */
export const hasLocale = (locale) => manager.hasLocale(locale);
/** Carrega locale em runtime a partir de um diretório de idiomas. */
export const loadLocale = (locale, options) => manager.loadLocale(locale, options);
/** Retorna o locale detectado no ambiente (sem fallback). */
export const getLocaleFromEnvironment = () => manager.getLocaleFromEnvironment();
export default manager;
